using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParentheses()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("0000000000", "(000) 000-0000")]
    [DataRow("9876543210", "(987) 654-3210")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithName_StartsWith_Dear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsCorrectGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    [DataRow("Jones", "Dr.", "Dear Dr. Jones,")]
    [DataRow("Lee", "Ms.", "Dear Ms. Lee,")]
    public void BuildGreeting_CustomTitle_ReturnsCorrectGreeting(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullOrWhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    [DataRow("My First Post!", "my-first-post")]
    [DataRow("  Spaces Around  ", "spaces-around")]
    [DataRow("Special @#$ Characters", "special-characters")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsWithExpected()
    {
        var result = _formatter.GenerateSlug("2024 Year in Review");

        Assert.StartsWith("2024", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithExpected()
    {
        var result = _formatter.GenerateSlug("Introduction to CSharp");

        Assert.EndsWith("csharp", result);
    }

    [TestMethod]
    public void GenerateSlug_NullOrWhitespace_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(""));
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow(10.5, "$10.50")]
    [DataRow(0.99, "$0.99")]
    [DataRow(1234.56, "$1234.56")]
    public void FormatCurrency_VariousAmounts_ReturnsFormattedString(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

